function mean_absolute_deviation(numbers) {
    if (numbers.length === 0) {
        return 0;
    }

    const mean = numbers.reduce((sum, num) => sum + num, 0) / numbers.length;

    const mad = numbers.reduce((sum, num) => sum + Math.abs(num - mean), 0) / numbers.length;

    return mad;
}
