function rolling_max(numbers) {
    if (numbers.length === 0) return [];

    const result = [];
    let currentMax = numbers[0];

    for (let i = 0; i < numbers.length; i++) {
        if (numbers[i] > currentMax) {
            currentMax = numbers[i];
        }
        result.push(currentMax);
    }

    return result;
}
