function make_palindrome(string) {
    if (string === "") return "";

    // Helper to check if a substring is a palindrome
    function isPalindrome(str) {
        const len = str.length;
        for (let i = 0; i < Math.floor(len / 2); i++) {
            if (str[i] !== str[len - 1 - i]) {
                return false;
            }
        }
        return true;
    }

    // Find the longest postfix of string that is a palindrome
    let start = 0;
    while (start < string.length) {
        const suffix = string.slice(start);
        if (isPalindrome(suffix)) {
            break;
        }
        start++;
    }

    // The prefix before the palindromic suffix
    const prefix = string.slice(0, start);

    // Reverse the prefix and append to the end of the original string
    const reversedPrefix = prefix.split('').reverse().join('');

    return string + reversedPrefix;
}
