function string_xor(a, b) {
    const len = Math.max(a.length, b.length);
    let result = '';
    for (let i = 0; i < len; i++) {
        const bitA = i < a.length ? parseInt(a[a.length - 1 - i], 10) : 0;
        const bitB = i < b.length ? parseInt(b[b.length - 1 - i], 10) : 0;
        result = (bitA ^ bitB).toString() + result;
    }
    return result;
}
